### 1.2 Object Pooling (Zero GC no Game Loop)

```typescript
// Pool de objetos reutilizáveis
class ObjectPool<T> {
  private pool: T[] = []
  private factory: () => T

  constructor(factory: () => T, initialSize = 100) {
    this.factory = factory
    // Pré-aloca
    for (let i = 0; i < initialSize; i++) {
      this.pool.push(factory())
    }
  }

  acquire(): T {
    return this.pool.pop() ?? this.factory()
  }

  release(obj: T): void {
    this.pool.push(obj)
  }
}

// Uso: Zero allocations no game loop
const vectorPool = new ObjectPool(() => ({ x: 0, y: 0 }), 1000)

function gameLoop() {
  const temp = vectorPool.acquire()  // Reutiliza
  temp.x = player.x + velocity.x
  temp.y = player.y + velocity.y
  // ... usa temp ...
  vectorPool.release(temp)  // Devolve ao pool
}
```

