## 2. Arquitetura de Store Vanilla (Framework-Agnostic)

### 2.1 Store Minimalista de Alta Performance

```typescript
// ═══════════════════════════════════════════════════════════════════════
// store/vanilla.ts - Core 100% independente de framework
// ═══════════════════════════════════════════════════════════════════════

type Listener<T> = (state: T, prevState: T) => void
type Selector<T, R> = (state: T) => R
type SetState<T> = (partial: Partial<T> | ((state: T) => Partial<T>)) => void

export interface VanillaStore<T> {
  getState: () => T
  setState: SetState<T>
  subscribe: (listener: Listener<T>) => () => void
  subscribeWithSelector: <R>(
    selector: Selector<T, R>,
    listener: (value: R, prev: R) => void,
    equalityFn?: (a: R, b: R) => boolean
  ) => () => void
  destroy: () => void
}

export function createStore<T extends object>(
  initialState: T | (() => T)
): VanillaStore<T> {
  // Estado interno (NÃO é proxy, NÃO é Immer)
  let state: T = typeof initialState === 'function' 
    ? (initialState as () => T)() 
    : initialState

  // Set de listeners (mais rápido que array para add/remove)
  const listeners = new Set<Listener<T>>()

  const getState = (): T => state

  const setState: SetState<T> = (partial) => {
    const prevState = state
    const nextPartial = typeof partial === 'function' 
      ? partial(state) 
      : partial

    // Shallow merge (sem Immer, sem proxy)
    state = { ...state, ...nextPartial }

    // Notifica listeners
    listeners.forEach(listener => listener(state, prevState))
  }

  const subscribe = (listener: Listener<T>) => {
    listeners.add(listener)
    return () => listeners.delete(listener)
  }

  // Subscription com selector (para bindings de framework)
  const subscribeWithSelector = <R>(
    selector: Selector<T, R>,
    listener: (value: R, prev: R) => void,
    equalityFn: (a: R, b: R) => boolean = Object.is
  ) => {
    let currentValue = selector(state)

    return subscribe((newState, prevState) => {
      const newValue = selector(newState)
      if (!equalityFn(currentValue, newValue)) {
        const prev = currentValue
        currentValue = newValue
        listener(newValue, prev)
      }
    })
  }

  const destroy = () => listeners.clear()

  return { getState, setState, subscribe, subscribeWithSelector, destroy }
}
```

