### 2.2 Store com TypedArrays para Dados de Alta Frequência

```typescript
// ═══════════════════════════════════════════════════════════════════════
// store/high-frequency.ts - Para dados que mudam a 60fps
// ═══════════════════════════════════════════════════════════════════════

export interface HighFrequencyStore {
  // Viewport (camera)
  viewport: Float32Array  // [x, y, zoom]

  // Mouse (atualiza a cada frame durante drag)
  mouse: Float32Array     // [x, y, deltaX, deltaY]

  // Momentum para inércia
  momentum: Float32Array  // [x, y]

  // Flags (usar Int8Array para booleans)
  flags: Int8Array        // [isDragging, isAnimating, ...]

  // Acesso direto (zero overhead)
  getViewportX: () => number
  getViewportY: () => number
  getZoom: () => number

  // Mutations diretas (sem spread, sem GC)
  setViewport: (x: number, y: number, zoom: number) => void
  addMomentum: (dx: number, dy: number) => void

  // Subscribe para quando PARAR de animar (sync com React)
  onSettle: (callback: () => void) => () => void
}

export function createHighFrequencyStore(): HighFrequencyStore {
  // Pré-alocação única
  const viewport = new Float32Array(3)  // x, y, zoom
  const mouse = new Float32Array(4)     // x, y, deltaX, deltaY
  const momentum = new Float32Array(2)  // x, y
  const flags = new Int8Array(8)        // booleans

  // Índices semânticos
  const FLAG_DRAGGING = 0
  const FLAG_ANIMATING = 1

  // Listeners para "settle" (quando animação termina)
  const settleListeners = new Set<() => void>()

  viewport[2] = 1  // zoom inicial = 1

  return {
    viewport,
    mouse,
    momentum,
    flags,

    getViewportX: () => viewport[0],
    getViewportY: () => viewport[1],
    getZoom: () => viewport[2],

    setViewport: (x, y, zoom) => {
      viewport[0] = x
      viewport[1] = y
      viewport[2] = zoom
    },

    addMomentum: (dx, dy) => {
      momentum[0] += dx
      momentum[1] += dy
    },

    onSettle: (callback) => {
      settleListeners.add(callback)
      return () => settleListeners.delete(callback)
    },
  }
}
```

