### 2.3 Composição: Store Híbrido Completo

```typescript
// ═══════════════════════════════════════════════════════════════════════
// store/game-store.ts - Combina vanilla + high-frequency
// ═══════════════════════════════════════════════════════════════════════

import { createStore, VanillaStore } from './vanilla'
import { createHighFrequencyStore, HighFrequencyStore } from './high-frequency'

// Estado "settled" (React-friendly)
interface GameState {
  // Domain data
  trains: Train[]
  tasks: TaskRender[]

  // Selection
  hoveredId: string | null
  selectedId: string | null

  // LOD (muda com zoom)
  lod: 'MACRO' | 'MESO' | 'MICRO'

  // Viewport "settled" (após drag/zoom terminar)
  settledViewport: { x: number; y: number; zoom: number }
}

export interface GameStore {
  // Store vanilla (para React/Vue bindings)
  state: VanillaStore<GameState>

  // Store high-frequency (para game loop)
  hf: HighFrequencyStore

  // Actions
  actions: {
    setHovered: (id: string | null) => void
    setSelected: (id: string | null) => void
    updateLOD: () => void
    settleViewport: () => void
  }
}

export function createGameStore(initialData: {
  trains: Train[]
  tasks: TaskRender[]
}): GameStore {
  const state = createStore<GameState>({
    trains: initialData.trains,
    tasks: initialData.tasks,
    hoveredId: null,
    selectedId: null,
    lod: 'MESO',
    settledViewport: { x: 0, y: 0, zoom: 1 },
  })

  const hf = createHighFrequencyStore()

  const actions = {
    setHovered: (id: string | null) => state.setState({ hoveredId: id }),
    setSelected: (id: string | null) => state.setState({ selectedId: id }),

    // Atualiza LOD baseado no zoom atual
    updateLOD: () => {
      const zoom = hf.getZoom()
      const newLOD = zoom < 0.5 ? 'MACRO' : zoom > 2 ? 'MICRO' : 'MESO'
      const current = state.getState().lod
      if (newLOD !== current) {
        state.setState({ lod: newLOD })
      }
    },

    // Sync HF → State (quando animação termina)
    settleViewport: () => {
      state.setState({
        settledViewport: {
          x: hf.getViewportX(),
          y: hf.getViewportY(),
          zoom: hf.getZoom(),
        }
      })
    },
  }

  return { state, hf, actions }
}

// Singleton global
export const gameStore = createGameStore({
  trains: [],
  tasks: [],
})
```

