## 3. Game Loop (requestAnimationFrame)

```typescript
// ═══════════════════════════════════════════════════════════════════════
// loop/game-loop.ts - Loop independente de React
// ═══════════════════════════════════════════════════════════════════════

import { gameStore } from '../store/game-store'

const FRICTION = 0.92
const MOMENTUM_THRESHOLD = 0.01

let animationId: number | null = null
let lastTime = 0

function tick(timestamp: number) {
  const delta = timestamp - lastTime
  lastTime = timestamp

  const { hf, actions } = gameStore

  // Aplica momentum (inércia)
  if (Math.abs(hf.momentum[0]) > MOMENTUM_THRESHOLD || 
      Math.abs(hf.momentum[1]) > MOMENTUM_THRESHOLD) {

    // Atualiza viewport diretamente (ZERO GC)
    hf.viewport[0] += hf.momentum[0]
    hf.viewport[1] += hf.momentum[1]

    // Aplica friction
    hf.momentum[0] *= FRICTION
    hf.momentum[1] *= FRICTION

    // Checa LOD
    actions.updateLOD()

  } else if (hf.flags[1] /* FLAG_ANIMATING */) {
    // Animação terminou → "settle"
    hf.flags[1] = 0
    actions.settleViewport()
  }

  animationId = requestAnimationFrame(tick)
}

export function startGameLoop() {
  if (animationId !== null) return
  lastTime = performance.now()
  animationId = requestAnimationFrame(tick)
}

export function stopGameLoop() {
  if (animationId !== null) {
    cancelAnimationFrame(animationId)
    animationId = null
  }
}
```

