## 4. Bindings para Frameworks

### 4.1 React Binding (useSyncExternalStore)

```typescript
// ═══════════════════════════════════════════════════════════════════════
// bindings/react.ts
// ═══════════════════════════════════════════════════════════════════════

import { useSyncExternalStore, useCallback } from 'react'
import { VanillaStore } from '../store/vanilla'
import { gameStore } from '../store/game-store'

// Hook genérico para qualquer store vanilla
export function useStore<T, R>(
  store: VanillaStore<T>,
  selector: (state: T) => R,
  equalityFn?: (a: R, b: R) => boolean
): R {
  const subscribe = useCallback(
    (onStoreChange: () => void) => {
      return store.subscribeWithSelector(
        selector,
        onStoreChange,
        equalityFn
      )
    },
    [store, selector, equalityFn]
  )

  const getSnapshot = useCallback(
    () => selector(store.getState()),
    [store, selector]
  )

  return useSyncExternalStore(subscribe, getSnapshot, getSnapshot)
}

// Hooks específicos para o GameStore
export function useGameState<R>(selector: (state: GameState) => R): R {
  return useStore(gameStore.state, selector)
}

export function useLOD() {
  return useGameState(s => s.lod)
}

export function useSelectedTask() {
  return useGameState(s => s.selectedId)
}

export function useTrains() {
  return useGameState(s => s.trains)
}

// Acesso imperativo para useFrame (R3F)
export function getViewport() {
  return {
    x: gameStore.hf.viewport[0],
    y: gameStore.hf.viewport[1],
    zoom: gameStore.hf.viewport[2],
  }
}
