### 4.2 Vue Binding (Composable)

```typescript
// ═══════════════════════════════════════════════════════════════════════
// bindings/vue.ts
// ═══════════════════════════════════════════════════════════════════════

import { ref, onMounted, onUnmounted, Ref } from 'vue'
import { VanillaStore } from '../store/vanilla'
import { gameStore } from '../store/game-store'

export function useStore<T, R>(
  store: VanillaStore<T>,
  selector: (state: T) => R
): Ref<R> {
  const value = ref(selector(store.getState())) as Ref<R>

  let unsubscribe: (() => void) | null = null

  onMounted(() => {
    unsubscribe = store.subscribeWithSelector(
      selector,
      (newValue) => { value.value = newValue }
    )
  })

  onUnmounted(() => {
    unsubscribe?.()
  })

  return value
}

// Composables específicos
export function useLOD() {
  return useStore(gameStore.state, s => s.lod)
}
