## 5. Uso em React Three Fiber

```tsx
// ═══════════════════════════════════════════════════════════════════════
// components/InfiniteCanvas.tsx
// ═══════════════════════════════════════════════════════════════════════

import { useFrame } from '@react-three/fiber'
import { useRef } from 'react'
import { OrthographicCamera } from 'three'
import { gameStore } from '../store/game-store'
import { useLOD } from '../bindings/react'

export function InfiniteCanvas() {
  const cameraRef = useRef<OrthographicCamera>(null)

  // ✅ Apenas LOD causa re-render
  const lod = useLOD()

  // ✅ 60fps: Lê TypedArray diretamente (ZERO re-renders)
  useFrame(() => {
    if (!cameraRef.current) return

    const { hf } = gameStore

    // Lê posição diretamente do Float32Array
    cameraRef.current.position.x = hf.viewport[0]
    cameraRef.current.position.y = hf.viewport[1]
    cameraRef.current.zoom = hf.viewport[2]
    cameraRef.current.updateProjectionMatrix()
  })

  return (
    <>
      <orthographicCamera ref={cameraRef} />
      {lod === 'MACRO' && <MacroLayer />}
      {lod === 'MESO' && <MesoLayer />}
      {lod === 'MICRO' && <MicroLayer />}
    </>
  )
}
```

